export default () => {
  self.addEventListener('message', function(e) { // eslint-disable-line no-restricted-globals
		if (e.data[0] === 'close') {
			self.close(); // eslint-disable-line no-restricted-globals
		} else {
      let dataArray = e.data[0];
      let parameters = e.data[1];

      let returnData = {};

			// Age variables
			let totalAgeSum = 0;
			let knownAges = 0;
			let totalDemocratAge = 0;
			let knownDemocratAges = 0;
			let totalRepublicanAge = 0;
			let knownRepublicanAges = 0;
			let totalNpaAge = 0;
			let knownNpaAges = 0;
			let totalOtherAge = 0;
			let knownOtherAges = 0;

			// total gender variables
			let males = 0;
			let females = 0;
			let unkownGenders = 0;

			// total race variables
			let blacks = 0;
			let whites = 0;
			let hispanics = 0;
			let otherRace = 0;

			// total party variables
			let republicans = 0;
			let democrats = 0;
			let npas = 0;
			let thirdPartyVoters = 0;

      // filter variables
      let totalFilteredVariables = 0;

      const titleCase = (str) => {
        str = str.toLowerCase().split(' ');
        for (let i = 0; i < str.length; i++) {
          str[i] = str[i].charAt(0).toUpperCase() + str[i].slice(1);
        }
        return str.join(' ');
      };

			for(let i=0; i<dataArray.length; i++) {
        if (parameters.ageFilter !== '') {
          switch (parameters.ageFilter) {
            case '1':
              if (parseInt(dataArray[i].Age, 10) >= 25) {
                continue;
              }
              break;
            case '2':
              if (parseInt(dataArray[i].Age, 10) < 26 || parseInt(dataArray[i].Age, 10) > 35) {
                continue;
              }
              break;
            case '3':
              if (parseInt(dataArray[i].Age, 10) < 36 || parseInt(dataArray[i].Age, 10) > 49) {
                continue;
              }
              break;
            case '4':
              if (parseInt(dataArray[i].Age, 10) < 50 || parseInt(dataArray[i].Age, 10) > 64) {
                continue;
              }
              break;
            case '5':
              if (parseInt(dataArray[i].Age, 10) < 65) {
                continue;
              }
              break;
          }
        }


        if (parameters.cityFilter !== '') {
          if (titleCase(dataArray[i].City) !== parameters.cityFilter) {
            continue;
          }
        }

        if (parameters.districtFilter !== '') {
          if (parseInt(dataArray[i].CountyCommissionDistrict, 10) !== parseInt(parameters.districtFilter, 10)) {
            continue;
          }
        }

        if (parameters.genderFilter !== '') {
          if (dataArray[i].Gender !== parameters.genderFilter) {
            continue;
          }
        }

        if (parameters.partyFilter !== '') {
          if (dataArray[i].Party !== parameters.partyFilter) {
            continue;
          }
        }

        if (parameters.precinctFilter !== '') {
          if (dataArray[i].Precinct !== parameters.precinctFilter) {
            continue;
          }
        }

        if (parameters.raceFilter !== '') {
          if (dataArray[i].Race !== parameters.raceFilter) {
            continue;
          }
        }

        if (parameters.zipFilter !== '') {
          if (dataArray[i].Zip !== parameters.zipFilter) {
            continue;
          }
        }

        totalFilteredVariables++;

				if (dataArray[i].Age !== '') {
					totalAgeSum += parseInt(dataArray[i].Age, 10);
					knownAges++;
				}
				switch (dataArray[i].Gender) {
					case 'F':
						females++;
						break;
					case 'M':
						males++;
						break;
					default:
						unkownGenders++;
						break;
				}
				switch (dataArray[i].Race) {
					case 'White':
						whites++;
						break;
					case 'Black':
						blacks++;
						break;
					case 'Hispanic':
						hispanics++;
						break;
					default:
						otherRace++;
						break;
				}
				switch (dataArray[i].Party) {
					case 'REP':
						republicans++;
						if (dataArray[i].Age !== '') {
							totalRepublicanAge += parseInt(dataArray[i].Age, 10);
							knownRepublicanAges++;
						}
						break;
					case 'DEM':
						democrats++;
						if (dataArray[i].Age !== '') {
							totalDemocratAge += parseInt(dataArray[i].Age, 10);
							knownDemocratAges++;
						}
						break;
					case 'NPA':
						npas++;
						if (dataArray[i].Age !== '') {
							totalNpaAge += parseInt(dataArray[i].Age, 10);
							knownNpaAges++;
						}
						break;
					default:
						thirdPartyVoters++;
						if (dataArray[i].Age !== '') {
							totalOtherAge += parseInt(dataArray[i].Age, 10);
							knownOtherAges++;
						}
						break;
				}
			}
			returnData.totalVoters = totalFilteredVariables;
			returnData.averageAge = (knownAges === 0) ? 0 : Math.round(totalAgeSum / knownAges);
			returnData.averageRepublicanAge = (knownRepublicanAges === 0) ? 0 : Math.round(totalRepublicanAge / knownRepublicanAges);
			returnData.averageDemocratAge = (knownDemocratAges === 0) ? 0 : Math.round(totalDemocratAge / knownDemocratAges);
			returnData.averageNpaAge = (knownNpaAges === 0) ? 0 : Math.round(totalNpaAge / knownNpaAges);
			returnData.averageOtherAge = (knownOtherAges === 0) ? 0 : Math.round(totalOtherAge / knownOtherAges);
			returnData.males = males;
			returnData.females = females;
			returnData.unkownGenders = unkownGenders;
			returnData.blacks = blacks;
			returnData.whites = whites;
			returnData.hispanics = hispanics;
			returnData.otherRace = otherRace;
			returnData.republicans = republicans;
			returnData.democrats = democrats;
			returnData.npas = npas;
			returnData.thirdPartyVoters = thirdPartyVoters;

      postMessage(returnData);
		}
	});
}
