export default () => {
  self.addEventListener('message', function(e) { // eslint-disable-line no-restricted-globals
		if (e.data[0] === 'close') {
			self.close(); // eslint-disable-line no-restricted-globals
		} else {
      let dataArray = e.data[0];

      let returnData = {
        ages: [],
        cities: [],
        districts: [],
        genders: [],
        parties: [],
        precincts: [],
        races: [],
        zips: []
      };

      const titleCase = (str) => {
        str = str.toLowerCase().split(' ');
        for (let i = 0; i < str.length; i++) {
          str[i] = str[i].charAt(0).toUpperCase() + str[i].slice(1);
        }
        return str.join(' ');
      };

			for (let i=0; i<dataArray.length; i++) {
        /*
        if (!returnData.ages.includes(dataArray[i].Age) && dataArray[i].Age !== '*') {
          returnData.ages.push(dataArray[i].Age);
        }
        */

        if (!returnData.cities.includes(titleCase(dataArray[i].City)) && dataArray[i].City !== '*') {
          returnData.cities.push(titleCase(dataArray[i].City));
        }

        if (!returnData.districts.includes(dataArray[i].CountyCommissionDistrict) && dataArray[i].CountyCommissionDistrict !== '*') {
          returnData.districts.push(dataArray[i].CountyCommissionDistrict);
        }

        if (!returnData.genders.includes(dataArray[i].Gender) && dataArray[i].Gender !== '*' && dataArray[i].Gender !== '') {
          returnData.genders.push(dataArray[i].Gender);
        }

        if (!returnData.parties.includes(dataArray[i].Party) && dataArray[i].Party !== '*') {
          returnData.parties.push(dataArray[i].Party);
        }

        if (!returnData.precincts.includes(dataArray[i].Precinct) && dataArray[i].Precinct !== '*') {
          returnData.precincts.push(dataArray[i].Precinct);
        }

        if (!returnData.races.includes(dataArray[i].Race) && dataArray[i].Race !== '*') {
          returnData.races.push(dataArray[i].Race);
        }

        if (!returnData.zips.includes(dataArray[i].Zip.slice(0, 5)) && dataArray[i].Zip !== '*') {
          returnData.zips.push(dataArray[i].Zip.slice(0, 5));
        }
      }

      postMessage(returnData);
		}
	});
}
