import { h, Component } from 'preact';
import style from './style';

// Import the Web Workers
import WebWorker from '../../workers/workerSetup';
import dataWorker from '../../workers/dataWorker';
import analyzingWorker from '../../workers/analyzingWorker';
import metaDataWorker from '../../workers/metaDataWorker';

export default class Home extends Component {

	constructor(props) {
		super(props);

		this.state = {
			county: '',
			data: [],
			averageAge: 0,
			averageDemocratAge: 0,
			averageNpaAge: 0,
			averageOtherAge: 0,
			averageRepublicanAge: 0,
			blacks: 0,
			democrats: 0,
			females: 0,
			hispanics: 0,
			males: 0,
			npas: 0,
			otherRace: 0,
			republicans: 0,
			thirdPartyVoters: 0,
			totalVoters: 0,
			unkownGenders: 0,
			whites: 0
		};
	}

	removeOptions = (selectbox, callback) => {
    var i;
    for(let i = selectbox.options.length - 1 ; i >= 0 ; i--) {
        selectbox.remove(i);
    }

		if (callback) {
			callback();
		}
	};

	loadCountyData = (county) => {
		let url = '';

		switch(county) {
			case 'Brevard':
				url = 'https://raw.githubusercontent.com/mgrigajtis/mgrigajtis.github.io/master/d5/data/data.json';
				break;
			case 'Citrus':
				url = 'https://raw.githubusercontent.com/mgrigajtis/mgrigajtis.github.io/master/citrus/data/data.json';
				break;
			default:
				this.setState({ data: [] });
				break;
		}

		if (county !== '') {
			let worker = new WebWorker(dataWorker);
			document.getElementById('countyLoading').classList.remove(style.hidden);

			worker.onmessage = (e) => {
				this.setState({ data: e.data.data });
				document.getElementById('countyLoading').classList.add(style.hidden);

				worker.postMessage(['close']);

				// Get the meta data
				let mdWorker = new WebWorker(metaDataWorker);
				document.getElementById('countyMetaData').classList.remove(style.hidden);

				mdWorker.onmessage = (e2) => {
					document.getElementById('countyMetaData').classList.add(style.hidden);

					mdWorker.postMessage(['close']);

					let districts = e2.data.districts.sort();
					let cities = e2.data.cities.sort();
					let genders = e2.data.genders.sort();
					let parties = e2.data.parties.sort();
					let precincts = e2.data.precincts.sort();
					let races = e2.data.races.sort();
					let zips = e2.data.zips.sort();

					this.removeOptions(document.getElementById('districtFilter'), () => {
						document.getElementById('districtFilter').options[0] = new Option('Select District', '');

						for (let i=0; i<districts.length; i++) {
							document.getElementById('districtFilter').options[i+1] = new Option(districts[i], districts[i]);
						}
					});

					this.removeOptions(document.getElementById('cityFilter'), () => {
						document.getElementById('cityFilter').options[0] = new Option('Select City', '');

						for (let i=0; i<cities.length; i++) {
							document.getElementById('cityFilter').options[i+1] = new Option(cities[i], cities[i]);
						}
					});

					this.removeOptions(document.getElementById('genderFilter'), () => {
						document.getElementById('genderFilter').options[0] = new Option('Select Gender', '');

						for (let i=0; i<genders.length; i++) {
							document.getElementById('genderFilter').options[i+1] = new Option(genders[i], genders[i]);
						}
					});

					this.removeOptions(document.getElementById('partyFilter'), () => {
						document.getElementById('partyFilter').options[0] = new Option('Select Party', '');

						for (let i=0; i<parties.length; i++) {
							document.getElementById('partyFilter').options[i+1] = new Option(parties[i], parties[i]);
						}
					});

					this.removeOptions(document.getElementById('precinctFilter'), () => {
						document.getElementById('precinctFilter').options[0] = new Option('Select Precinct', '');

						for (let i=0; i<precincts.length; i++) {
							document.getElementById('precinctFilter').options[i+1] = new Option(precincts[i], precincts[i]);
						}
					});

					this.removeOptions(document.getElementById('raceFilter'), () => {
						document.getElementById('raceFilter').options[0] = new Option('Select Race', '');

						for (let i=0; i<races.length; i++) {
							document.getElementById('raceFilter').options[i+1] = new Option(races[i], races[i]);
						}
					});

					this.removeOptions(document.getElementById('zipFilter'), () => {
						document.getElementById('zipFilter').options[0] = new Option('Select Zip Code', '');

						for (let i=0; i<zips.length; i++) {
							document.getElementById('zipFilter').options[i+1] = new Option(zips[i], zips[i]);
						}
					});
				};

				mdWorker.postMessage([e.data.data]);
			};

			worker.postMessage([url]);
		}
	};

	countyChanged = (e) => {
		this.setState({ county: e.target.value } );

		this.loadCountyData(e.target.value);
	};

	analyzeData = () => {
		let worker = new WebWorker(analyzingWorker);
		document.getElementById('countyProcessing').classList.remove(style.hidden);

		let ageFilter = document.getElementById('ageFilter').value;
		let cityFilter = document.getElementById('cityFilter').value;
		let districtFilter = document.getElementById('districtFilter').value;
		let genderFilter = document.getElementById('genderFilter').value;
		let partyFilter = document.getElementById('partyFilter').value;
		let precinctFilter = document.getElementById('precinctFilter').value;
		let raceFilter = document.getElementById('raceFilter').value;
		let zipFilter = document.getElementById('zipFilter').value;

		let parameters = {
			ageFilter: ageFilter,
			cityFilter: cityFilter,
			districtFilter: districtFilter,
			genderFilter: genderFilter,
			partyFilter: partyFilter,
			precinctFilter: precinctFilter,
			raceFilter: raceFilter,
			zipFilter: zipFilter
		};

		worker.onmessage = (e) => {
			let returnData = e.data;
			document.getElementById('countyProcessing').classList.add(style.hidden);

			this.setState({
				averageAge: returnData.averageAge,
				averageDemocratAge: returnData.averageDemocratAge,
				averageNpaAge: returnData.averageNpaAge,
				averageOtherAge: returnData.averageOtherAge,
				averageRepublicanAge: returnData.averageRepublicanAge,
				blacks: returnData.blacks,
				democrats: returnData.democrats,
				females: returnData.females,
				hispanics: returnData.hispanics,
				males: returnData.males,
				npas: returnData.npas,
				otherRace: returnData.otherRace,
				republicans: returnData.republicans,
				thirdPartyVoters: returnData.thirdPartyVoters,
				totalVoters: returnData.totalVoters,
				unkownGenders: returnData.unkownGenders,
				whites: returnData.whites
			});

			worker.postMessage(['close']);
		};

		worker.postMessage([this.state.data, parameters]);
	};

	render() {
		return (
			<div class={style.home}>
				<div class={style.debug}>
					Selected County: {this.state.county}<br />
					Total Voters: {this.state.data.length}<br />
					Filtered Voters: {this.state.totalVoters}<br />
					Average Age: {this.state.averageAge}<br />
					Average Democrat Age: {this.state.averageDemocratAge}<br />
					Average NPA Age: {this.state.averageNpaAge}<br />
					Average Other Age: {this.state.averageOtherAge}<br />
					Average Republican Age: {this.state.averageRepublicanAge}<br />
					Blacks: {this.state.blacks}<br />
					Hispanics: {this.state.hispanics}<br />
					Other Race: {this.state.otherRace}<br />
					Whites: {this.state.whites}<br />
					Females: {this.state.females}<br />
					Males: {this.state.males}<br />
					Unkown Genders: {this.state.unkownGenders}<br />
					Democrats: {this.state.democrats}<br />
					Republicans: {this.state.republicans}<br />
					NPAs: {this.state.npas}<br />
					Third Party Voters: {this.state.thirdPartyVoters}<br />
				</div>

				<div>
					<label for="county">Select County</label><br />
					<select id="county" onChange={this.countyChanged}>
						<option value="">Select County</option>
						<option value="Brevard">Brevard</option>
						<option value="Citrus">Citrus</option>
					</select>
					<span class={style.hidden} id="countyLoading">Loading...</span>
					<span class={style.hidden} id="countyMetaData">Gathering Meta Data...</span>
					<span class={style.hidden} id="countyProcessing">Processing...</span>
				</div>

				<div>
				<label for="ageFilter">Filter By Age Range</label><br />
					<select id="ageFilter">
						<option value=''>Select Age Range</option>
						<option value='1'>18 - 25</option>
						<option value='2'>26 - 35</option>
						<option value='3'>36 - 49</option>
						<option value='4'>50 - 64</option>
						<option value='5'>65+</option>
					</select>
				</div>

				<div>
					<label for="cityFilter">Filter By City</label><br />
					<select id="cityFilter"></select>
				</div>

				<div>
					<label for="districtFilter">Filter By District</label><br />
					<select id="districtFilter"></select>
				</div>

				<div>
					<label for="genderFilter">Filter By Gender</label><br />
					<select id="genderFilter"></select>
				</div>

				<div>
					<label for="partyFilter">Filter By Party</label><br />
					<select id="partyFilter"></select>
				</div>

				<div>
					<label for="precinctFilter">Filter By Precinct</label><br />
					<select id="precinctFilter"></select>
				</div>

				<div>
					<label for="raceFilter">Filter By Race</label><br />
					<select id="raceFilter"></select>
				</div>

				<div>
					<label for="zipFilter">Filter By Zip Code</label><br />
					<select id="zipFilter"></select>
				</div>

				<div>
					<button onClick={this.analyzeData}>Analyze</button>
				</div>
			</div>
		);
	}
}
